# BGE-style asymmetric fine-tuning
QUERY_PREFIX = "Represent this sentence for searching relevant passages: "
PASSAGE_PREFIX = ""   # BGE passages have no prefix

def make_asymmetric_examples(qa_pairs: list[dict]) -> list[InputExample]:
    """Wrap queries with prefix; leave passages bare."""
    return [
        InputExample(
            texts=[
                QUERY_PREFIX + item["query"],
                item["passage"],            # positive
            ]
        )
        for item in qa_pairs
    ]

# During inference, apply the same prefix
def embed_query(model: SentenceTransformer, query: str) -> np.ndarray:
    return model.encode(QUERY_PREFIX + query, normalize_embeddings=True)

def embed_passage(model: SentenceTransformer, passage: str) -> np.ndarray:
    return model.encode(passage, normalize_embeddings=True)
